"use strict";parserFactory.register("mydramanovel.com",()=>new MydramanovelParser);class MydramanovelParser extends Parser{constructor(){super(),this.minimumThrottle=3e3}async getChapterUrls(e){return[...e.querySelectorAll(".td-big-grid-flex-posts .entry-title a, .tdb-category-loop-posts .entry-title a")].map(e=>this.hyperLinkToChapter(e))}hyperLinkToChapter(e){return{sourceUrl:e.href,title:e.getAttribute("title")||e.textContent}}findContent(e){let t=e.querySelector(".tdb_single_content .tdb-block-inner");if(null==t&&(t=e.querySelector("div.td-post-content, .td-post-content")),null==t){let r=e.querySelector(".tdb-block-inner");r&&r.textContent.trim().length>50&&(t=r)}return t}async fetchChapter(e){let t={parser:this};return(await HttpClient.wrapFetch(e,t)).responseXML}isCustomError(e){let t=e?.responseXML?.querySelector("title")?.textContent||"";if("Just a moment..."===t||t.includes("Cloudflare")||t.includes("Attention Required!"))return!0;let r=e?.responseXML?.body?.textContent?.trim()||"",n=e?.responseXML?.querySelector(".tdb_single_content, .td-post-content, .tdb-block-inner");return!n&&r.length<500}setCustomErrorResponse(e,t,r){let n={};return n.url=e,n.wrapOptions=t,n.response={url:r.response.url,status:403},n.errorMessage="mydramanovel.com requested a Cloudflare check or blocked the request. Try switching the CORS proxy or using direct mode.",n}extractTitleImpl(e){return e.querySelector("h1.tdb-title-text")}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){let t=e.querySelector(".td-big-grid-flex-posts .td-module-thumb span[data-img-url]");return t?t.getAttribute("data-img-url")??null:null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.tdb_category_description .tdb-block-inner")]}}